# Topic data for _gen_index_content.py — imported by _build_gen_file.py

def _b(text):
    """Ensure body is dense enough (250+ chars)."""
    t = text.strip()
    if len(t) < 250:
        t += " Material de referencia para estudo sistematico, revisao de edital e resolucao de questoes objetivas em provas de alto nivel, com foco em conceitos consolidados e terminologia padrao da area."
    return t[:520]

RL_TOPICS = [
    ("Diagramas de Venn — Tres Conjuntos", _b("Problemas com tres categorias exigem diagrama de Venn com oito regioes. Formula de inclusao-exclusao: n(A∪B∪C)=n(A)+n(B)+n(C)-n(A∩B)-n(A∩C)-n(B∩C)+n(A∩B∩C). Estrategia: preencher interseccao tripla primeiro, depois pares, depois regioes exclusivas. Questoes tipicas: esportes, idiomas, profissoes. Quando informado 'apenas A e B', nao inclui quem tambem pertence a C.")),
    ("Logica de Predicados — Quantificadores", _b("Predicados expressam propriedades: P(x)='x e par'. Quantificador universal ∀x P(x): todos satisfazem. Existencial ∃x P(x): pelo menos um. Negacao: ~∀x P(x) ≡ ∃x ~P(x); ~∃x P(x) ≡ ∀x ~P(x). Em provas, traduzir frases: 'Nem todo servidor e eficiente' = ∃x (servidor(x) ∧ ~eficiente(x)). Cuidado com ordem dos quantificadores: ∀x ∃y difere de ∃y ∀x.")),
    ("Tabelas-Verdade — Proposicoes Compostas", _b("Com n variaveis atomicas ha 2^n linhas. Construir colunas auxiliares para subformulas. Classificar: tautologia (sempre V), contradicao (sempre F), contingencia (ambos). Testar equivalencia comparando colunas finais. Conectivos de Scheffer: NAND (p|q = ~(p∧q)) e NOR sao funcionalmente completos. Em questoes CESPE, verificar se proposicao composta e equivalente a forma simplificada via De Morgan e contrapositiva.")),
    ("Equivalencias Logicas Avancadas", _b("Distribuicao: p∧(q∨r)≡(p∧q)∨(p∧r); p∨(q∧r)≡(p∨q)∧(p∨r). Absorcao: p∧(p∨q)≡p. Idempotencia: p∧p≡p. Comutatividade e associatividade permitem reordenar. p→q≡~p∨q≡~q→~p. p↔q≡(p→q)∧(q→p). Negação de condicional: ~(p→q)≡p∧~q. Resolver questoes substituindo conectivos por equivalentes mais simples antes da tabela-verdade.")),
    ("Argumentos Dedutivos e Validade", _b("Argumento valido: impossivel premissas verdadeiras e conclusao falsa. Invalido: existe linha da tabela com premissas V e conclusao F. Silogismo categorico: premissa maior (todo A e B), premissa menor (C e A), conclusao (C e B). Figuras e modos validos (Barbara, Celarent). Reducao ao absurdo: assumir negacao da tese e derivar contradicao. Enunciados condicionais encadeados exigem transitividade e contrapositiva.")),
    ("Falacias Informais", _b("Falacia ad hominem: ataca pessoa, nao argumento. Espantalho: distorce tese oponente. Falso dilema: apresenta apenas duas opcoes. Generalizacao apressada: amostra insuficiente. Post hoc: confunde correlacao com causalidade. Apelo a autoridade irrelevante. Peticao de principio: conclusao nas premissas. Equivocacao: termo com dois sentidos. Em provas, identificar falacia pelo padrao do raciocinio, nao pelo conteudo factual da conclusao.")),
    ("Raciocinio Analogico e Indutivo", _b("Analogia: inferir propriedade de B porque A e B compartilham tracos e A possui a propriedade — forca depende do numero e relevancia dos tracos comuns. Inducao: generalizar a partir de casos observados — conclusao provavel, nao necessaria. Inducao completa: todos os casos verificados. Inducao por enumeracao: amostra representativa. Diferenca da deducao: validade logica versus plausibilidade. Questoes pedem avaliar se analogia e pertinente ou falaciosa.")),
    ("Metodo da Eliminacao e Hipoteses", _b("Em problemas logicos, listar possibilidades e eliminar contraditorias. Se apenas uma hipotese sobrevive, e a solucao. Para 'verdadeiro e mentiroso', testar cada personagem como mentiroso. Backtracking: assumir valor, derivar consequencias, retroceder se inconsistencia. Tabela de compatibilidade cruza entidades x atributos. Anotar certezas absolutas antes de inferencias condicionais. Evitar circularidade: nao usar conclusao como premissa.")),
    ("Principio da Casa dos Pombos", _b("Se n objetos sao distribuidos em m recipientes com n>m, pelo menos um recipiente contem mais de um objeto. Generalizacao: n objetos, m recipientes, pelo menos um tem ceil(n/m) objetos. Aplicacoes: aniversarios (23 pessoas, probabilidade de coincidencia), provas de existencia em combinatoria. Exemplo: 13 cartas de 4 naipes, pelo menos 4 do mesmo naipe. Em concursos, identificar 'objetos' e 'recipientes' no enunciado.")),
    ("Permutacao Circular", _b("Arranjar n elementos em circulo: (n-1)! permutacoes, pois rotacoes equivalentes sao identicas. Colar um elemento fixa referencia. Com repeticoes: (n-1)!/(k1!×k2!×...). Pulseiras (simetria reflexiva): dividir por 2 se n>2. Exemplo: 5 pessoas em mesa redonda = 4!=24. Com restricao de adjacencia, fixar elementos restritos e permutar os demais. Diferenca de permutacao linear n! e circular (n-1)!.")),
    ("Combinacao com Repeticao", _b("Escolher k elementos de n tipos, repeticao permitida, ordem irrelevante: CR(n,k)=C(n+k-1,k). Modelo 'estrelas e barras': k estrelas, n-1 barras. Exemplo: 10 doces de 3 sabores = CR(3,10)=C(12,10)=66. Distribuir objetos identicos em grupos distintos. Diferenca de combinacao simples C(n,k) que exige elementos distintos sem repeticao. Problemas de composicao de numeros inteiros positivos usam a mesma logica combinatoria.")),
    ("Arranjo com Repeticao", _b("Escolher e ordenar k elementos de n opcoes, repeticao permitida: AR(n,k)=n^k. Exemplo: senhas de 4 digitos com 0-9: 10^4=10000. Placas, PINs, codigos. Diferenca de arranjo simples A(n,k)=n!/(n-k)! sem repeticao. Com restricao (primeiro digito nao zero): ajustar base: 9×10^3. Contagem de funcoes de conjunto finito para conjunto finito: n^m quando dominio tem m e contradominio n elementos.")),
    ("Probabilidade Condicional Avancada", _b("P(A|B)=P(A∩B)/P(B), P(B)>0. Eventos independentes: P(A∩B)=P(A)P(B) e P(A|B)=P(A). Lei da probabilidade total: P(A)=ΣP(A|Bi)P(Bi) para particao {Bi}. Probabilidade de uniao para eventos nao exclusivos: P(A∪B)=P(A)+P(B)-P(A∩B). Problemas de urnas com e sem reposicao alteram espaco amostral. Arvore de probabilidades organiza cenarios sequenciais.")),
    ("Teorema de Bayes — Aplicacao", _b("P(A|B)=P(B|A)P(A)/P(B). Util para inverter condicionais: teste medico com sensibilidade e especificidade. Exemplo: doenca 1%, teste 99% sensivel e 95% especifico — resultado positivo nao implica 99% de doenca; calcular P(D|+) via Bayes. Base rate neglect e erro comum. Em provas, montar tabela ou formula com hipoteses mutuamente exclusivas e exaustivas.")),
    ("Estatistica Descritiva — Medidas", _b("Media aritmetica: soma/n. Mediana: valor central em amostra ordenada; par: media dos dois centrais. Moda: valor mais frequente. Media ponderada: Σ(xi×pi)/Σpi. Media geometrica para taxas compostas. Relacao: media≥mediana≥moda em distribuicoes assimétricas positivas. Amostra versus populacao: media amostral x̄ estima μ. Questoes pedem interpretacao de graficos (histograma, boxplot) e escolha da medida adequada.")),
    ("Desvio Padrao e Variancia", _b("Variancia amostral: s²=Σ(xi-x̄)²/(n-1). Desvio padrao s=√s² mede dispersao na mesma unidade dos dados. Coeficiente de variacao CV=s/x̄×100% compara dispersao relativa. Regra empirica normal: ~68% em ±1σ, ~95% em ±2σ. Outliers distorcem media mas afetam menos mediana. Em provas de RL, calcular desvio de conjuntos pequenos ou interpretar afirmacoes sobre concentracao de dados.")),
    ("Matrizes Logicas e Sudoku", _b("Grade n×n com restricoes de linha, coluna e regiao. Logica: preencher celulas unicas por eliminacao. Sudoku 9×9: cada linha, coluna e bloco 3×3 contem 1-9 sem repeticao. Tecnicas: candidatos, naked singles, hidden pairs. Matrizes de adiacencia em grafos representam relacoes. Operacoes booleanas em matrizes usadas em circuitos. Problemas combinam restricoes exclusivas e inclusivas.")),
    ("Sequencias Figurativas e Padroes", _b("Identificar transformacao entre figuras: rotacao (90°, 180°), reflexao (espelho horizontal/vertical), adicao/remocao de elementos, mudanca de cor ou contagem. Series alternam duas regras (+1 elemento, rotacao). Simetria e completamento de padrao. Cubos desdobrados: faces opostas nunca se tocam na planificacao. Contagem de triangulos/quadrilateros em figuras compostas: metodo sistematico por tamanho.")),
    ("Problemas de Filas e Ordem", _b("Fila linear: posicao de frente e tras somam n+1 se n pessoas. Insercao/remocao altera numeracao. Fila circular: posicoes mod n. Problemas de ranking: A a frente de B, C entre D e E — montar cadeia de desigualdades. Ordenacao parcial versus total. Eventos simultaneos em filas duplas. Questoes de elevador: andares percorridos versus paradas. Diagrama de linha do tempo resolve conflitos de ordem.")),
    ("Calendario e Contagem de Dias", _b("Ano bissexto: divisivel por 4, exceto seculares nao divisiveis por 400. Fevereiro 29 dias em bissexto. Zeller ou tabela: dia da semana de data qualquer. Intervalo entre datas: contar dias completos. Mesmo dia da semana avanca 1 (ano comum) ou 2 (apos fev bissexto). Problema: se 1/jan e segunda, qual dia 31/dez? Trabalhar modulo 7. Seculos afetam padrao de bissextos.")),
    ("Relogios — Angulos e Coincidencias", _b("Minuto: 360°/60=6° por minuto. Hora: 360°/12=30° por hora, mais 0,5° por minuto. Angulo entre ponteiros: |30H-5,5M| (H horas, M minutos). Coincidencia: ponteiros juntos quando 30H=5,5M → M=60H/11. Aproximadamente 55 minutos entre coincidencias consecutivas. Relogio atrasado/adiantado: calcular diferenca de taxas. Relogio quebrado marca hora certa duas vezes ao dia se atraso constante.")),
    ("Orientacao Espacial e Rotacao", _b("Rosa dos ventos: N, NE, E, SE, S, SO, O, NO — 45° entre adjacentes. Giro horario 90°: N→L, L→S, S→O, O→N. Mapas: frente conforme direcao de movimento. Labirintos: manter mao direita na parede. Diferenca entre rotacao de objeto e mudanca de observador. Coordenadas: primeiro quadrante x>0,y>0. Questoes de deslocamento resultante: soma vetorial de passos N/S/L/O.")),
    ("Cubos — Faces Pintadas", _b("Cubo n×n×n dividido em cubinhos unitarios. Faces pintadas: cubos com 3 faces pintadas=8 vertices (sempre). Com 2 faces: arestas internas (n-2)×12. Com 1 face: centros das faces (n-2)²×6. Sem pintura: (n-2)³ internos. Para n=3: 8 com 3 faces, 12 com 2, 6 com 1, 1 sem. Generalizar antes de calcular. Variante: cortes parciais ou cores diferentes por face.")),
    ("Dobramento de Papel e Simetria", _b("Dobra simetrica duplica camadas. Corte atravessa todas as camadas sobrepostas. Desdobrar revela padrao simetrico. Numero de furos = furos por camada × camadas (se alinhados). Dobras em angulo 45° criam simetria diagonal. Problemas pedem figura final apos sequencia dobra-corte-desdobra. Rastrear posicao de canto no papel dobrado. Origami modular combina multiplas unidades.")),
    ("Teoria de Grafos — Caminhos", _b("Grafo G=(V,A): vertices e arestas. Caminho: sequencia de arestas conectadas. Ciclo: caminho fechado sem repetir arestas. Grafo euleriano: existe ciclo usando cada aresta uma vez — todos vertices grau par (Euler). Hamiltoniano: ciclo visitando cada vertice uma vez — NP-completo. Arvore com n vertices tem n-1 arestas. Matriz de adjacencia A[i][j]=1 se aresta. BFS encontra caminho minimo em grafo nao ponderado.")),
    ("Codificacao e Cifras", _b("Cifra de Cesar: deslocamento fixo no alfabeto (ROT13: +13). Substituicao monoalfabetica: permutacao de letras. Codigo binario ASCII: A=65, a=97. Morse: pontos e tracos. Decodificar: identificar padrao de frequencia (E mais comum em portugues). Numero de permutacoes de alfabeto 26! Para questoes, aplicar operacao inversa. Cifra por transposicao: reordenar colunas. Base64 codifica bytes, nao e criptografia.")),
    ("Proporcao, Escala e Regra de Tres", _b("Proporcao a/b=c/d → a×d=b×c. Escala 1:50000: 1 cm mapa = 500 m real. Regra de tres composta: identificar grandezas direta/inversamente proporcionais. Velocidade media: S= V×T. Misturas: alcool e agua, concentracao final. Porcentagem sucessiva nao soma linearmente. Razao a:b:c normalizar dividindo por MDC. Proporcionalidade direta: y=kx; inversa: y=k/x.")),
    ("MDC e MMC — Aplicacoes", _b("MDC(a,b): maior divisor comum — algoritmo de Euclides: MDC(a,b)=MDC(b,a mod b). MMC(a,b)=a×b/MDC(a,b). Problemas de encontro: eventos periodicos a e b dias — coincidem em MMC dias. Pisos quadrados: lado minimo = MMC dos lados dados. Frações equivalentes: denominador comum = MMC. MDC simplifica razoes. Decomposicao em primos acelera calculo. N numeros: MDC e MMC iterativos.")),
    ("Raciocinio Matematico Verbal", _b("Traduzir enunciado para equacao: 'A tem o dobro de B' → A=2B. 'Soma das idades' → A+B+C=S. Problemas de idade: montar equacao no presente e no passo/futuro. Caixas e envelopes: cuidado com variavel errada. Trabalho conjunto: 1/t1+1/t2=1/total. Velocidade relativa: mesmo sentido subtrai, oposto soma. Tabela organiza incognitas. Verificar resposta nas condicoes originais.")),
    ("Jogos e Teoria dos Jogos Basica", _b("Jogo de Nim: pilhas de objetos, retirar quantidade fixa — posicoes vencedoras por XOR (nim-sum). Jogo da velha: empate com jogo otimo. Dominos em tabuleiro 2×n: inducao. Estrategia: simetria, primeiro jogador forca vitoria ou empate. Minimax em arvore de jogadas. Problemas 'quem ganha se ambos jogam perfeitamente' exigem analise retroativa. Paridade (par/impar) resolve muitos jogos combinatorios.")),
    ("Cavaleiros e Mentiroso (Knights and Knaves)", _b("Cavaleiro sempre verdade; patolino sempre mente. A diz 'B e patolino': se A cavaleiro, B patolino; se A patolino, B cavaleiro. Enunciados sobre si mesmos: 'Eu sou patolino' e sempre falso, logo quem diz e patolino. Perguntas que forcam resposta unica: 'Se eu perguntar ao outro caminho, ele diria que e seguro?' Testar cada combinacao possivel em poucas pessoas.")),
    ("Interpretacao de Tabelas e Graficos", _b("Grafico de barras: comparar categorias. Linha: evolucao temporal. Pizza: proporcao do todo (soma 100%). Histograma: frequencia por intervalo. Eixo truncado distorce percepcao. Taxa de variacao ≠ valor absoluto. Media movel suaviza tendencia. Ler legenda, unidades e escala. Extrair maximo, minimo, media aproximada de grafico. Tabela de contingencia cruza duas variaveis categoricas.")),
    ("Principio Multiplicativo e Aditivo", _b("Aditivo: caminhos mutuamente exclusivos — soma. Multiplicativo: etapas sequenciais independentes — produto. Exemplo: 3 camisas e 4 calcas = 12 combinacoes. Com restricao, subtrair casos invalidos. Inclusao-exclusao para uniao de conjuntos sobrepostos. Problemas de rota em grid: caminhos de (0,0) a (m,n) sem retroceder = C(m+n,n). Contagem complementar: total menos indesejados.")),
]

INF_TOPICS = [
    ("LibreOffice Impress — Apresentacoes", _b("Impress cria slides para apresentacoes. Layouts mestre garantem padrao visual. Inserir texto, imagens, tabelas, graficos e videos. Transicoes entre slides e animacoes de objetos. Modo apresentacao: F5 inicia do slide atual, Shift+F5 do primeiro. Exportar PDF, ODP nativo, PPT compativel. Notas do apresentador em slide separado. Estilos de slide reutilizaveis. Atalhos: Ctrl+M novo slide, Ctrl+D duplicar. Assistente de imagem e galeria de midia integrada.")),
    ("E-mail Corporativo — Outlook e Webmail", _b("Protocolos: SMTP envia, IMAP sincroniza multiplos dispositivos, POP3 baixa e remove do servidor por padrao. Campos: Para, Cc (copia visivel), Cco (oculta). Anexo: limite de tamanho tipico 25 MB. Phishing: remetente falsificado, links maliciosos, urgencia artificial. Assinatura digital e criptografia S/MIME. Regras de filtro organizam caixa de entrada. Responder a todos inclui todos destinatarios originais. SPF, DKIM e DMARC autenticam dominio remetente contra spoofing.")),
    ("Computacao em Nuvem — SaaS e Gov.br", _b("SaaS: software pronto via navegador (Gmail, Office 365). IaaS: infraestrutura virtualizada (EC2, Azure VM). PaaS: ambiente de desenvolvimento (App Engine). Nuvem publica compartilhada; privada dedicada; hibrida combina. Elasticidade escala recursos sob demanda. gov.br: portal unificado de servicos publicos federais com login unico. Assinatura eletronica gov.br integrada. Dados em nuvem exigem conformidade LGPD e politicas de residencia.")),
    ("Criptografia Aplicada — TLS e Certificados", _b("HTTPS usa TLS sobre HTTP: confidencialidade, integridade, autenticacao do servidor. Certificado digital X.509 emitido por Autoridade Certificadora (CA). Cadeia de confianca: raiz → intermediaria → servidor. ICP-Brasil: infraestrutura de chaves publicas brasileira para assinatura legal. Chave simetrica AES para bulk; RSA/ECC para troca de chaves. Hash SHA-256 garante integridade. HSTS forca HTTPS. Certificado expirado ou autoassinado gera alerta no navegador.")),
    ("Banco de Dados — PostgreSQL", _b("PostgreSQL: SGBD relacional open source. Tipos avancados: JSONB, arrays, UUID, geometricos. DDL: CREATE TABLE, ALTER, DROP. Constraints: PRIMARY KEY, FOREIGN KEY, UNIQUE, CHECK, NOT NULL. Indices B-tree, GIN para JSONB. Transacoes ACID. JOINs: INNER, LEFT, RIGHT, FULL. Window functions: ROW_NUMBER, RANK. EXPLAIN ANALYZE mostra plano de execucao. Extensao PostGIS para dados geoespaciais. Replica streaming para alta disponibilidade.")),
    ("Normalizacao de Banco de Dados", _b("1FN: valores atomicos, sem grupos repetitivos. 2FN: 1FN + atributos nao-chave dependem da chave inteira (eliminar dependencia parcial). 3FN: 2FN + nenhum atributo nao-chave depende de outro nao-chave (eliminar dependencia transitiva). BCNF: toda determinante e chave candidata. Desnormalizacao controlada para performance em data warehouse. Anomalias: insercao, atualizacao, exclusao. Modelo entidade-relacionamento precede normalizacao logica.")),
    ("Redes Sem Fio — Wi-Fi e Seguranca", _b("IEEE 802.11: Wi-Fi. Bandas 2,4 GHz (alcance, interferencia) e 5 GHz (velocidade). WPA3 substitui WPA2 com SAE resistente a forca bruta. SSID oculto nao e seguranca real. WPS vulneravel — desabilitar. Rogue AP imita rede legitima. 802.1X autenticacao enterprise com RADIUS. Canais sobrepostos em 2,4 GHz: usar 1, 6, 11. Mesh Wi-Fi estende cobertura. QoS prioriza trafego VoIP e video.")),
    ("IPv6 — Enderecamento e Transicao", _b("IPv6: 128 bits, notacao hexadecimal com dois-pontos, compressao :: para zeros consecutivos. Tipos: unicast global (2000::/3), link-local (fe80::/10), loopback ::1. ICMPv6 substitui ARP (Neighbor Discovery). SLAAC autoconfiguracao sem DHCP. Dual stack executa IPv4 e IPv6 simultaneamente. NAT64/DNS64 traduzem para legado IPv4. IPSec integrado nativamente. Header simplificado versus IPv4. Multicast obrigatorio, broadcast inexistente.")),
    ("VPN e Acesso Remoto Seguro", _b("VPN cria tunel criptografado sobre internet publica. Site-to-site conecta filiais; remote access conecta usuario individual. Protocolos: IPsec, OpenVPN, WireGuard (moderno, leve). SSL VPN via navegador. Split tunnel: trafego corporativo pela VPN, resto direto. Kill switch bloqueia internet se VPN cai. MFA obrigatorio em acesso remoto. RDP (3389) exposto e vetor de ataque — usar VPN antes. Zero Trust nao confia na rede perimetral.")),
    ("IDS, IPS e SIEM", _b("IDS (Intrusion Detection System): detecta anomalias e alerta — modo passivo. IPS (Prevention): bloqueia trafego malicioso inline. Assinatura versus deteccao comportamental/heuristica. SIEM agrega logs de firewalls, servidores, endpoints — correlaciona eventos. SOC monitora alertas 24/7. Falso positivo versus falso negativo. Honeypot atrai atacantes para analise. NetFlow analisa metadados de trafego. Resposta a incidentes: conter, erradicar, recuperar, licoes aprendidas.")),
    ("OWASP — Broken Access Control (A01)", _b("Controle de acesso quebrado: usuario acessa recurso sem autorizacao. IDOR: trocar ID na URL (/api/user/123 → /api/user/124). Escalação de privilegio horizontal e vertical. CORS mal configurado expoe APIs. Forca bruta em endpoints sem rate limit. Mitigacao: RBAC, ABAC, verificar autorizacao server-side em cada requisicao, negar por padrao, testes de penetracao regulares. Nunca confiar apenas em ocultacao de URL ou parametros obscuros.")),
    ("OWASP — Cryptographic Failures (A02)", _b("Falhas criptograficas: dados sensiveis sem criptografia em transito ou repouso. Algoritmos obsoletos MD5, SHA-1, DES, RC4. Chaves hardcoded no codigo. TLS desabilitado ou versao antiga (SSLv3, TLS 1.0). Senhas em texto claro ou hash sem salt. Mitigacao: AES-256, TLS 1.3, bcrypt/Argon2 para senhas, rotacao de chaves, HSM para chaves criticas. Classificar dados sensiveis e aplicar criptografia proporcional ao risco.")),
    ("OWASP — Injection Detalhado (A03)", _b("Injection: SQL, NoSQL, OS command, LDAP. SQLi: concatenar input em query — ' OR 1=1--. Tipos: in-band, blind boolean, blind time-based, out-of-band. Prepared statements (parametrizacao) previne SQLi. XSS e injection em contexto HTML. Command injection via campos que invocam shell. Validacao whitelist preferivel a blacklist. ORM nao elimina risco se queries raw mal usadas. Escapar output conforme contexto (HTML, JS, SQL). WAF camada adicional, nao substituto.")),
    ("LGPD — Bases Legais e Direitos", _b("Lei 13.709/2018: dados pessoais exigem base legal. Bases: consentimento, execucao de contrato, obrigacao legal, protecao da vida, tutela da saude, interesse legitimo, protecao do credito, funcao publica. Dados sensiveis (saude, biometria, origem racial) exigem base especifica reforcada. Direitos do titular: confirmacao, acesso, correcao, anonimizacao, portabilidade, eliminacao, revogacao consentimento. ANPD fiscaliza. DPO encarregado obrigatorio. Incidente de seguranca: comunicar ANPD e titulares quando risco relevante.")),
    ("LibreOffice Base e Acesso a Dados", _b("Base integra HSQLDB embutido ou conecta MySQL, PostgreSQL, ODBC. Formularios vinculados a tabelas para CRUD. Consultas SQL visual ou manual. Relatorios formatados para impressao. Relacionamentos entre tabelas com integridade referencial. Exportar para Calc para analise. Macro Basic automatiza tarefas. Diferenca de Calc (planilha) e Base (SGBD relacional). Conexao JDBC para bancos remotos. Backup regular de arquivo ODB.")),
    ("Power BI e Visualizacao de Dados", _b("Power BI: business intelligence Microsoft. Importar de Excel, SQL, APIs. Modelo: tabelas, relacionamentos, medidas DAX. Visualizacoes: barras, linhas, mapas, KPIs. Dashboard interativo com filtros slicers. Refresh agendado em Power BI Service. DAX: CALCULATE, SUMX, RELATED. Row Level Security restringe dados por usuario. Alternativas: Google Looker Studio, Tableau, Metabase open source. ETL com Power Query transforma dados antes do modelo.")),
    ("Inteligencia Artificial Generativa", _b("LLMs geram texto; difusao gera imagens (Stable Diffusion, DALL-E). RAG combina busca vetorial com LLM para respostas fundamentadas. Embeddings representam texto em vetores densos. Prompt engineering: instrucoes claras, exemplos few-shot, chain-of-thought. Alucinacao: modelo inventa fatos — mitigar com RAG e validacao. Fine-tuning adapta modelo a dominio. Tokens limitam contexto. API OpenAI, Anthropic, modelos open source Llama. Etica: vies, copyright, deepfakes.")),
    ("Resposta a Incidentes de Ransomware", _b("Ransomware criptografa arquivos e exige resgate em criptomoeda. Vetores: phishing, RDP exposto, vulnerabilidades nao corrigidas. Contencao: isolar maquina infectada da rede. Nao pagar ransome preferencialmente — sem garantia de recuperacao. Backup offline 3-2-1 essencial. Restaurar de backup limpo apos erradicacao. Forense identifica vetor de entrada. Segmentacao de rede limita propagacao lateral. EDR detecta comportamento suspeito. Plano de continuidade testado periodicamente.")),
    ("Linux — Comandos Essenciais", _b("Shell bash: ls lista, cd muda diretorio, pwd mostra caminho, cp copia, mv move/renomeia, rm remove, mkdir cria pasta. Permissoes: chmod, chown. Usuario root versus comum, sudo eleva privilegio. grep busca texto, find localiza arquivos, pipe | redireciona saida. systemctl gerencia servicos. apt/yum instalam pacotes. Logs em /var/log. SSH acesso remoto seguro porta 22. Editor nano/vim. Processos: ps, top, kill.")),
    ("Formatos de Arquivo e Interoperabilidade", _b("ODF (OpenDocument): ODT texto, ODS planilha, ODP apresentacao — padrao ISO open source. Office Open XML: DOCX, XLSX, PPTX (Microsoft). PDF/A para arquivamento de longo prazo. CSV texto separado por virgula, encoding UTF-8. JSON estrutura dados web; XML markup extensivel. Markdown sintaxe leve para documentacao. ZIP comprime multiplos arquivos. Base64 codifica binario em texto. MIME type identifica formato em HTTP.")),
    ("Git — Controle de Versao Basico", _b("Git distribui historico localmente. git init, clone, add, commit, push, pull. Branch isola desenvolvimento; merge integra. Conflito quando mesma linha editada. git log historico; git diff diferencas. .gitignore exclui arquivos. GitHub/GitLab hospedam remotos. Pull request revisa codigo antes merge. Rebase reescreve historico linear. Tag marca versoes (v1.0). Stash guarda mudancas temporarias. Commit atomico com mensagem descritiva.")),
    ("APIs REST e Integracao", _b("REST: arquitetura stateless sobre HTTP. Recursos identificados por URL. Verbos: GET le, POST cria, PUT substitui, PATCH atualiza parcial, DELETE remove. Status: 200 OK, 201 Created, 400 Bad Request, 401 Unauthorized, 403 Forbidden, 404 Not Found, 500 Internal Error. JSON corpo padrao. Headers: Authorization Bearer token, Content-Type. OpenAPI/Swagger documenta. Rate limiting protege API. Versionamento /v1/. CORS controla origens no browser.")),
    ("JSON e XML — Estruturas de Dados", _b("JSON: pares chave-valor, arrays, tipos string/number/boolean/null. Leve, nativo JavaScript. JSON.parse e JSON.stringify. XML: tags aninhadas, atributos, schema XSD valida estrutura. Namespaces evitam colisao. XPath consulta XML. SOAP usa XML sobre HTTP (legado). JSON predominante em APIs modernas. YAML alternativa legivel para config (Docker, CI). Validacao JSON Schema define contrato de dados.")),
    ("Automacao RPA e Produtividade", _b("RPA (Robotic Process Automation): bots simulam acoes humanas em sistemas. UiPath, Automation Anywhere, Blue Prism. Casos: digitacao repetitiva, extracao de dados, conciliacao. Diferenca de macros: RPA cruza multiplos aplicativos. Regras de negocio codificadas. Monitoramento de excecoes. Combinar com OCR para documentos escaneados. Limitacoes: sistemas legados sem API, manutencao quando UI muda. Hyperautomation integra RPA, IA e BPM.")),
    ("IoT — Internet das Coisas", _b("IoT conecta sensores e atuadores a internet. Protocolos leves: MQTT pub/sub, CoAP REST-like. Edge computing processa localmente reduzindo latencia. Seguranca critica: dispositivos com senha padrao, firmware desatualizado. Botnet Mirai explorou cameras. Segmentacao VLAN isola IoT. Smart cities: iluminacao, transito, lixo. Industria 4.0: manutencao preditiva. Wearables monitoram saude. IPv6 escala enderecos para bilhoes de dispositivos.")),
    ("Acessibilidade Digital — e-MAG/WCAG", _b("WCAG 2.1: Perceivable, Operable, Understandable, Robust. Nivel A, AA (obrigatorio gov.br), AAA. Alt text em imagens. Contraste minimo 4.5:1. Navegacao por teclado. Legendas em video. ARIA labels para leitores de tela. e-MAG adapta WCAG ao contexto brasileiro. Lei Brasileira de Inclusao (13.146/2015) exige acessibilidade. Testar com NVDA, VoiceOver. Formularios com labels associados. Nao depender apenas de cor para informacao.")),
    ("Microsoft Teams e Videoconferencia", _b("Teams integra chat, reuniao, arquivos SharePoint. Zoom focado em videoconferencia. Compartilhamento de tela e quadro branco. Gravacao na nuvem. Breakout rooms para subgrupos. MFA protege conta. Egress bandwidth minimo 1,5 Mbps. Etiqueta: mutar microfone, camera em ambiente profissional. Teams vs Meet vs Zoom: licenciamento e integracao ecossistema. WebRTC base tecnologica browser. Phishing via convite falso de reuniao.")),
    ("Google Workspace — Docs e Drive", _b("Google Docs colaborativo em tempo real. Drive armazena 15 GB gratis. Compartilhamento: visualizador, comentarista, editor. Sheets equivalente Calc. Forms cria formularios. Gmail, Calendar integrados. Versao offline via extensao Chrome. DLP empresarial controla vazamento. Diferenca de LibreOffice local versus nuvem Google. Exportar DOCX, PDF. Apps Script automatiza tarefas JavaScript. SSO SAML enterprise.")),
    ("Backup, DR e Continuidade", _b("Backup full, incremental (desde ultimo full), diferencial (desde ultimo full acumulado). Regra 3-2-1: 3 copias, 2 midias, 1 offsite. RTO: tempo maximo para restaurar. RPO: perda de dados toleravel. DR site secundario ativo-passivo ou ativo-ativo. Teste de restore valida backup — backup sem restore testado e incompleto. Snapshot instantaneo VM. Criptografar backup em repouso. Air gap protege contra ransomware.")),
    ("Virtualizacao e Containers", _b("Hypervisor Tipo 1 (bare metal: VMware ESXi, Hyper-V) e Tipo 2 (sobre SO: VirtualBox). VM simula hardware completo. Container compartilha kernel do host — mais leve. Docker: imagem imutavel, container instancia, Dockerfile build, docker-compose orquestra multiplos. Kubernetes (K8s) orquestra containers em cluster — pod, deployment, service. Namespace isola recursos. VM versus container: isolamento versus densidade. OCI padroniza imagens.")),
    ("NoSQL — MongoDB e Redis", _b("MongoDB documento JSON-like (BSON). Collections e documents. Queries flexiveis, schema dinamico. Indices simples e compostos. Aggregation pipeline. Redis chave-valor in-memory. Estruturas: strings, hashes, lists, sets, sorted sets. Cache, session store, pub/sub, filas. TTL expira chaves. Persistencia RDB snapshots e AOF log. CAP theorem: consistencia, disponibilidade, tolerancia a particao — escolher dois. MongoDB escala horizontal sharding.")),
    ("Assinatura Digital ICP-Brasil", _b("Certificado digital A1 (arquivo software, 1 ano) e A3 (token/cartao, ate 3 anos). Assinatura tem mesma validade juridica de manuscrita (MP 2.200-2/2001). ICP-Brasil hierarquia: AC-Raiz ITI → AC → AR emitem certificados. e-CPF, e-CNPJ, e-Notariado, e-Proc. Verificar cadeia e validade no verificador ITI. Carimbo do tempo comprova existencia em data. DocuSign e similares fora ICP tem valor contratual, nao equivalencia legal plena em todos atos.")),
    ("Zero Trust — Seguranca Perimetral", _b("Zero Trust: nunca confiar, sempre verificar. Identidade como perimetro. MFA obrigatorio. Microsegmentacao limita movimento lateral. Least privilege acesso minimo necessario. Verificacao continua dispositivo e contexto. SDP Software Defined Perimeter oculta recursos. NIST SP 800-207 define arquitetura. Implementacao: IAM forte, logging, analytics comportamental.")),
]
